#!/bin/bash\n#\n# HIVE OS Test Suite\n# Comprehensive testing of all HIVE components\n# Author: KRACKERJACK1134\n#\n\nset -euo pipefail\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nTEST_RESULTS=\"${SCRIPT_DIR}/test_results.txt\"\nPASSED=0\nFAILED=0\nWARNINGS=0\n\n# Colors\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nNC='\\033[0m' # No Color\n\necho \"═══════════════════════════════════════════════════════════════\"\necho \"  HIVE OS COMPREHENSIVE TEST SUITE\"\necho \"  Prime Directive: ASSIMILATE OR DIE\"\necho \"═══════════════════════════════════════════════════════════════\"\necho \"\"\necho \"Tests will begin in 5 seconds...\"\necho \"\"\nsleep 5\n\ntest_result() {\n    local test_name=\"$1\"\n    local result=\"$2\"\n    local message=\"${3:-}\"\n    \n    if [ \"$result\" = \"PASS\" ]; then\n        echo -e \"${GREEN}✓ PASS${NC}: $test_name\"\n        ((PASSED++))\n    elif [ \"$result\" = \"FAIL\" ]; then\n        echo -e \"${RED}✗ FAIL${NC}: $test_name - $message\"\n        ((FAILED++))\n    else  # WARN\n        echo -e \"${YELLOW}⚠ WARN${NC}: $test_name - $message\"\n        ((WARNINGS++))\n    fi\n}\n\necho \"[1/12] Testing Core Build...\"\nif make clean > /dev/null 2>&1 && make > /dev/null 2>&1; then\n    test_result \"Core build\" \"PASS\"\nelse\n    test_result \"Core build\" \"FAIL\" \"Build failed\"\nfi\necho \"\"\n\necho \"[2/12] Testing hive-test...\"\nif [ -f \"./hive-test\" ] && ./hive-test > /dev/null 2>&1; then\n    test_result \"Personality test\" \"PASS\"\nelse\n    test_result \"Personality test\" \"FAIL\" \"hive-test failed\"\nfi\necho \"\"\n\necho \"[3/12] Testing libhive.so...\"\nif [ -f \"./libhive.so\" ]; then\n    test_result \"Personality library\" \"PASS\"\nelse\n    test_result \"Personality library\" \"FAIL\" \"libhive.so not found\"\nfi\necho \"\"\n\necho \"[4/12] Testing pam_hive.so...\"\nif [ -f \"./pam_hive.so\" ]; then\n    test_result \"PAM module\" \"PASS\"\nelse\n    test_result \"PAM module\" \"FAIL\" \"pam_hive.so not found\"\nfi\necho \"\"\n\necho \"[5/12] Testing hive-init...\"\nif [ -f \"./hive-init\" ]; then\n    test_result \"Bootstrap tool\" \"PASS\"\nelse\n    test_result \"Bootstrap tool\" \"FAIL\" \"hive-init not found\"\nfi\necho \"\"\n\necho \"[6/12] Testing hive-shell...\"\nif [ -f \"./hive-shell\" ]; then\n    test_result \"Custom shell\" \"PASS\"\nelse\n    test_result \"Custom shell\" \"FAIL\" \"hive-shell not found\"\nfi\necho \"\"\n\necho \"[7/12] Testing Overlay Structure...\"\nif [ -d \"overlay/hive-os\" ] && [ -d \"overlay/metadata\" ]; then\n    test_result \"Portage overlay\" \"PASS\"\nelse\n    test_result \"Portage overlay\" \"FAIL\" \"Overlay structure incomplete\"\nfi\necho \"\"\n\necho \"[8/12] Testing Ebuilds...\"\nif [ -f \"overlay/hive-os/hive-core/hive-core-1.0.0.ebuild\" ] && \\\n   [ -f \"overlay/hive-os/hive-personality/hive-personality-1.0.0.ebuild\" ] && \\\n   [ -f \"overlay/hive-os/hive-kernel-module/hive-kernel-module-1.0.0.ebuild\" ] && \\\n   [ -f \"overlay/hive-os/hive-systemd/hive-systemd-1.0.0.ebuild\" ] && \\\n   [ -f \"overlay/hive-os/hive-audit/hive-audit-1.0.0.ebuild\" ] && \\\n   [ -f \"overlay/hive-os/hive-zorg/hive-zorg-1.0.0.ebuild\" ] && \\\n   [ -f \"overlay/hive-os/hive-meta/hive-meta-1.0.0.ebuild\" ]; then\n    test_result \"Ebuild files\" \"PASS\"\nelse\n    test_result \"Ebuild files\" \"FAIL\" \"Some ebuilds missing\"\nfi\necho \"\"\n\necho \"[9/12] Testing Configuration Files...\"\nif [ -f \"overlay/hive-os/hive-core/files/default-gentoo.conf\" ] && \\\n   [ -f \"overlay/hive-os/hive-core/files/default-termux.conf\" ]; then\n    test_result \"Default configs\" \"PASS\"\nelse\n    test_result \"Default configs\" \"FAIL\" \"Config files missing\"\nfi\necho \"\"\n\necho \"[10/12] Testing PAM Configuration...\"\nif [ -f \"overlay/hive-os/hive-pam/files/hive-system-auth\" ] && \\\n   [ -f \"overlay/hive-os/hive-pam/files/hive-sshd\" ] && \\\n   [ -f \"overlay/hive-os/hive-pam/files/hive-su\" ]; then\n    test_result \"PAM configs\" \"PASS\"\nelse\n    test_result \"PAM configs\" \"FAIL\" \"PAM config files missing\"\nfi\necho \"\"\n\necho \"[11/12] Testing Systemd Integration...\"\nif [ -f \"overlay/hive-os/hive-systemd/files/hive-personality.service\" ] && \\\n   [ -f \"overlay/hive-os/hive-systemd/files/hive-personality.timer\" ] && \\\n   [ -f \"overlay/hive-os/hive-systemd/files/hive-audit.service\" ] && \\\n   [ -f \"overlay/hive-os/hive-systemd/files/hive-collective-sync.service\" ]; then\n    test_result \"Systemd services\" \"PASS\"\nelse\n    test_result \"Systemd services\" \"FAIL\" \"Service files missing\"\nfi\necho \"\"\n\necho \"[12/12] Testing Documentation...\"\nif [ -f \"docs/INSTALLATION.md\" ] && [ -f \"docs/CONFIGURATION.md\" ] && [ -f \"README.md\" ]; then\n    test_result \"Documentation\" \"PASS\"\nelse\n    test_result \"Documentation\" \"WARN\" \"Some docs missing\"\nfi\necho \"\"\n\necho \"═══════════════════════════════════════════════════════════════\"\necho \"  TEST SUMMARY\"\necho \"═══════════════════════════════════════════════════════════════\"\necho -e \"${GREEN}Passed:${NC}  $PASSED/12\"\necho -e \"${RED}Failed:${NC}  $FAILED/12\"\necho -e \"${YELLOW}Warned:${NC}  $WARNINGS/12\"\necho \"\"\n\nif [ $FAILED -eq 0 ]; then\n    echo -e \"${GREEN}✓ ALL TESTS PASSED${NC}\"\n    echo \"\"\n    echo \"HIVE OS is ready for installation!\"\n    exit 0\nelse\n    echo -e \"${RED}✗ SOME TESTS FAILED${NC}\"\n    exit 1\nfi\n